// Filter: score >= 40, not applied, LinkedIn Easy Apply only
const jobs = $json.jobs || $json.classified || $json.results || [];
const qualified = [];

for (const job of jobs) {
  const score = job.match_score || job.score || 0;
  if (score < 40) continue;
  if (job.status === 'applied' || job.already_applied) continue;
  if (job.expired) continue;
  const platform = (job.platform || '').toLowerCase();
  if (!platform.includes('linkedin')) continue;
  if (!job.easy_apply && job.application_type !== 'linkedin_easy_apply') continue;

  qualified.push({
    json: {
      id: job.id || job.job_id,
      title: job.title,
      company: job.company,
      url: job.url,
      platform: 'linkedin',
      score,
      easy_apply: job.easy_apply || true,
      poster_name: job.poster_name || null,
      poster_linkedin_url: job.poster_linkedin_url || null,
      applicant_count: job.applicant_count || null,
      description: (job.description || '').substring(0, 3000),
      location: job.location || 'Remote',
      ats_type: job.ats_type || null
    }
  });
}

if (qualified.length === 0) {
  return [{ json: { _empty: true, total_searched: jobs.length, message: 'No qualified LinkedIn Easy Apply jobs found' } }];
}

// Sort by score DESC, cap at 25/run
qualified.sort((a, b) => b.json.score - a.json.score);
return qualified.slice(0, 25);

parameters.text:
=Research this company for a job application:

Job: {{ $json.title }}
Company: {{ $json.company }}
Location: {{ $json.location }}
Job Description: {{ $json.description }}

Provide:
1. Company overview (2-3 sentences: what they do, size, stage)
2. Tech stack / tools they use (based on JD clues)
3. Key pain point this role solves
4. Tone of the company (startup/corporate/agency)
5. Any red flags (vague JD, unrealistic expectations, etc.)

Be concise. Output as JSON: { company_overview, tech_stack, pain_point, company_tone, red_flags, skip_recommended }

parameters.jsCode:
// Check if Company Intel Agent recommends skipping
const intel = $json.output || $json;
let parsed = intel;
if (typeof intel === 'string') {
  try { parsed = JSON.parse(intel) } catch { parsed = { skip_recommended: false } }
}

if (parsed.skip_recommended) {
  return [{ json: { _skip: true, reason: parsed.red_flags || 'Company intel recommends skip', ...$('N5. Filter & Sort').first().json } }];
}

return [{ json: {
  ...$('N5. Filter & Sort').first().json,
  company_intel: parsed
} }];

