// Route based on apply result
const result = $json;
const status = result.status || 'failed';

const job = $('N7b. Skip Check').first().json;
const recruiter = $('N8. Recruiter Discovery Agent').first().json?.output || {};
const connectionNote = $('N10. Connection Note Generator').first().json?.output || $('N10. Connection Note Generator').first().json?.text || '';

return [{ json: {
  apply_status: status,
  apply_result: result,
  job_id: job.id,
  job_title: job.title,
  company: job.company,
  job_url: job.url,
  platform: 'linkedin',
  recruiter_linkedin_url: recruiter.recruiter_linkedin_url || job.poster_linkedin_url,
  recruiter_id: result.recruiter_id || null,
  connection_note: connectionNote,
  should_connect: !!(recruiter.recruiter_linkedin_url || job.poster_linkedin_url),
  should_email: !!(recruiter.recruiter_email && recruiter.email_confidence !== 'none')
} }];

